package integration

import (
	"bytes"
	"context"
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/grpc-ecosystem/grpc-gateway/v2/runtime"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	errs "go.flipt.io/flipt/errors"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/internal/server/evaluation"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	"go.uber.org/zap/zaptest"
)

// mockEvaluationStore implements the evaluation.Storer interface for testing
type mockEvaluationStore struct {
	flags             map[string]*flipt.Flag
	evaluationRules   map[string][]*storage.EvaluationRule
	evaluationRollouts map[string][]*storage.EvaluationRollout
}

func (m *mockEvaluationStore) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	key := req.Namespace + ":" + req.Key
	flag, exists := m.flags[key]
	if !exists {
		return nil, errs.ErrNotFound(req.Key)
	}
	return flag, nil
}

func (m *mockEvaluationStore) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	key := req.Namespace + ":" + req.Key
	rules, exists := m.evaluationRules[key]
	if !exists {
		return []*storage.EvaluationRule{}, nil
	}
	return rules, nil
}

func (m *mockEvaluationStore) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
	return []*storage.EvaluationDistribution{}, nil
}

func (m *mockEvaluationStore) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	key := req.Namespace + ":" + req.Key
	rollouts, exists := m.evaluationRollouts[key]
	if !exists {
		return []*storage.EvaluationRollout{}, nil
	}
	return rollouts, nil
}

// setupTestServer creates a test HTTP server with the evaluation service registered
func setupTestServer(store *mockEvaluationStore) *httptest.Server {
	logger := zaptest.NewLogger(&testing.T{})
	evalServer := evaluation.New(logger, store)

	mux := runtime.NewServeMux()
	err := rpcevaluation.RegisterEvaluationServiceHandlerServer(
		context.Background(),
		mux,
		evalServer,
	)
	if err != nil {
		panic(err)
	}

	return httptest.NewServer(mux)
}

// TestBooleanEvaluationSuccess tests successful boolean flag evaluation
func TestBooleanEvaluationSuccess(t *testing.T) {
	store := &mockEvaluationStore{
		flags: map[string]*flipt.Flag{
			"default:feature-enabled": {
				NamespaceKey: "default",
				Key:          "feature-enabled",
				Enabled:      true,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			},
		},
		evaluationRollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := setupTestServer(store)
	defer server.Close()

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "test-request-1",
		NamespaceKey: "default",
		FlagKey:      "feature-enabled",
		EntityId:     "user-123",
		Context: map[string]string{
			"email": "user@example.com",
		},
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	resp, err := http.Post(
		server.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		respBody, _ := io.ReadAll(resp.Body)
		t.Fatalf("expected status %d, got %d: %s", http.StatusOK, resp.StatusCode, string(respBody))
	}

	var boolResp rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&boolResp)
	require.NoError(t, err)

	assert.True(t, boolResp.Enabled, "expected feature to be enabled")
	assert.Equal(t, "feature-enabled", boolResp.FlagKey)
	assert.Equal(t, "test-request-1", boolResp.RequestId)
	assert.NotZero(t, boolResp.RequestDurationMillis)
}

