// TestBooleanEvaluationFlagNotFound tests error handling when flag is not found
func TestBooleanEvaluationFlagNotFound(t *testing.T) {
	store := &mockEvaluationStore{
		flags:              map[string]*flipt.Flag{},
		evaluationRollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := setupTestServer(store)
	defer server.Close()

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "test-request-4",
		NamespaceKey: "default",
		FlagKey:      "nonexistent-flag",
		EntityId:     "user-000",
	}

	body, err := json.Marshal(req)
	require.NoError(t, err)

	resp, err := http.Post(
		server.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Expect an error response (typically 404 or 500 depending on error handling)
	if resp.StatusCode == http.StatusOK {
		t.Fatalf("expected non-200 status, got %d", resp.StatusCode)
	}

	// Verify we get an error response
	respBody, _ := io.ReadAll(resp.Body)
	assert.NotEmpty(t, respBody, "expected error message in response body")
}

