// TestBatchEvaluationMultipleFlags tests batch evaluation with multiple flags
func TestBatchEvaluationMultipleFlags(t *testing.T) {
	store := &mockEvaluationStore{
		flags: map[string]*flipt.Flag{
			"default:flag-1": {
				NamespaceKey: "default",
				Key:          "flag-1",
				Enabled:      true,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			},
			"default:flag-2": {
				NamespaceKey: "default",
				Key:          "flag-2",
				Enabled:      false,
				Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
			},
		},
		evaluationRollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := setupTestServer(store)
	defer server.Close()

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-request-1",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-1",
				NamespaceKey: "default",
				FlagKey:      "flag-1",
				EntityId:     "user-batch-1",
			},
			{
				RequestId:    "req-2",
				NamespaceKey: "default",
				FlagKey:      "flag-2",
				EntityId:     "user-batch-2",
			},
		},
	}

	body, err := json.Marshal(batchReq)
	require.NoError(t, err)

	resp, err := http.Post(
		server.URL+"/evaluate/v1/batch",
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		respBody, _ := io.ReadAll(resp.Body)
		t.Fatalf("expected status %d, got %d: %s", http.StatusOK, resp.StatusCode, string(respBody))
	}

	var batchResp rpcevaluation.BatchEvaluationResponse
	err = json.NewDecoder(resp.Body).Decode(&batchResp)
	require.NoError(t, err)

	assert.Equal(t, "batch-request-1", batchResp.RequestId)
	assert.Len(t, batchResp.Responses, 2, "expected 2 responses in batch")

	// Verify first response
	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type)
	if boolResp := batchResp.Responses[0].GetBooleanResponse(); boolResp != nil {
		assert.True(t, boolResp.Enabled)
		assert.Equal(t, "flag-1", boolResp.FlagKey)
	} else {
		t.Fatal("expected boolean response for first item")
	}

	// Verify second response
	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[1].Type)
	if boolResp := batchResp.Responses[1].GetBooleanResponse(); boolResp != nil {
		assert.False(t, boolResp.Enabled)
		assert.Equal(t, "flag-2", boolResp.FlagKey)
	} else {
		t.Fatal("expected boolean response for second item")
	}
}

