// mockEvaluationStore implements the evaluation.Storer interface for testing
type mockEvaluationStore struct {
	flags             map[string]*flipt.Flag
	evaluationRules   map[string][]*storage.EvaluationRule
	evaluationRollouts map[string][]*storage.EvaluationRollout
}

func (m *mockEvaluationStore) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	key := req.Namespace + ":" + req.Key
	flag, exists := m.flags[key]
	if !exists {
		return nil, errs.ErrNotFound(req.Key)
	}
	return flag, nil
}

func (m *mockEvaluationStore) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	key := req.Namespace + ":" + req.Key
	rules, exists := m.evaluationRules[key]
	if !exists {
		return []*storage.EvaluationRule{}, nil
	}
	return rules, nil
}

func (m *mockEvaluationStore) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
	return []*storage.EvaluationDistribution{}, nil
}

func (m *mockEvaluationStore) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	key := req.Namespace + ":" + req.Key
	rollouts, exists := m.evaluationRollouts[key]
	if !exists {
		return []*storage.EvaluationRollout{}, nil
	}
	return rollouts, nil
}

// setupTestServer creates a test HTTP server with the evaluation service registered
func setupTestServer(store *mockEvaluationStore) *httptest.Server {
	logger := zaptest.NewLogger(&testing.T{})
	evalServer := evaluation.New(logger, store)

	mux := runtime.NewServeMux()
	err := rpcevaluation.RegisterEvaluationServiceHandlerServer(
		context.Background(),
		mux,
		evalServer,
	)
	if err != nil {
		panic(err)
	}

	return httptest.NewServer(mux)
}

