	require.Equal(t, http.StatusOK, resp1.StatusCode, "namespace-a evaluation should succeed")

	var boolResp1 rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp1.Body).Decode(&boolResp1)
	require.NoError(t, err)
	assert.True(t, boolResp1.Enabled)

	// Evaluate in namespace-b
	req2 := &rpcevaluation.EvaluationRequest{
		RequestId:    "scope-test-2",
		NamespaceKey: "namespace-b",
		FlagKey:      "scoped-flag",
		EntityId:     "user-scope-2",
	}

	body2, err := json.Marshal(req2)
	require.NoError(t, err)

	resp2, err := http.Post(
		server.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader(body2),
	)
	require.NoError(t, err)
	defer resp2.Body.Close()

	require.Equal(t, http.StatusOK, resp2.StatusCode, "namespace-b evaluation should succeed")

	var boolResp2 rpcevaluation.BooleanEvaluationResponse
	err = json.NewDecoder(resp2.Body).Decode(&boolResp2)
	require.NoError(t, err)
	assert.False(t, boolResp2.Enabled, "namespace-b flag should be disabled")
}

// TestInvalidRequestBody tests behavior with malformed request bodies
func TestInvalidRequestBody(t *testing.T) {
	store := &mockEvaluationStore{
		flags:              map[string]*flipt.Flag{},
		evaluationRollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := setupTestServer(store)
	defer server.Close()

	// Send invalid JSON
	resp, err := http.Post(
		server.URL+"/evaluate/v1/boolean",
		"application/json",
		bytes.NewReader([]byte("{ invalid json")),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Should receive an error (typically 400)
	if resp.StatusCode == http.StatusOK {
		t.Fatalf("expected non-200 status for invalid JSON, got %d", resp.StatusCode)
	}

	respBody, _ := io.ReadAll(resp.Body)
	assert.NotEmpty(t, respBody, "expected error message in response body")
}

